function drawDiagonalBorders() {
  const parents = document.querySelectorAll(".wp-block-services");

  parents.forEach((parent) => {
    const canvas = parent.querySelector(".services-lines");
    if (!canvas) return;

    const ctx = canvas.getContext("2d");

    function performDraw() {
      // 1. Get current dimensions
      const rect = parent.getBoundingClientRect();
      const parentWidth = Math.floor(rect.width);
      const parentHeight = Math.floor(rect.height);

      // 2. Safety Check: If size is invalid or massive (sanity check), exit
      if (
        parentWidth <= 0 ||
        parentHeight <= 0 ||
        parentWidth > 5000 ||
        parentHeight > 5000
      ) {
        return;
      }

      // 3. Handle High DPI (Retina) with a Cap
      // Capping at 2x even if the screen is 3x or 4x to prevent "Exceeds Max Size" errors
      const dpr = Math.min(window.devicePixelRatio || 1, 3);

      // Limit the internal buffer to a safe maximum (e.g., 4096px)
      const MAX_SAFE_SIZE = 4096;
      let bufferWidth = parentWidth * dpr;
      let bufferHeight = parentHeight * dpr;

      if (bufferWidth > MAX_SAFE_SIZE || bufferHeight > MAX_SAFE_SIZE) {
        const scaleDown = Math.min(
          MAX_SAFE_SIZE / bufferWidth,
          MAX_SAFE_SIZE / bufferHeight,
        );
        bufferWidth *= scaleDown;
        bufferHeight *= scaleDown;
      }

      canvas.width = bufferWidth;
      canvas.height = bufferHeight;

      // Reset transform and scale to map the buffer to the CSS size
      ctx.setTransform(1, 0, 0, 1, 0, 0);
      ctx.scale(bufferWidth / parentWidth, bufferHeight / parentHeight);

      // 4. Get Styles
      const style = window.getComputedStyle(parent);
      const pt = parseFloat(style.paddingTop) || 0;
      const pb = parseFloat(style.paddingBottom) || 0;
      const pl = parseFloat(style.paddingLeft) || 0;
      const pr = parseFloat(style.paddingRight) || 0;

      const contentW = parentWidth - pl - pr;
      const contentH = parentHeight - pt - pb;

      if (contentW <= 0 || contentH <= 0) return;

      const colWidth = contentW / 12;
      const spacing = parentWidth < 600 ? 12 : 16;

      // 5. Drawing Logic
      ctx.clearRect(0, 0, parentWidth, parentHeight);

      const strokeColor =
        style.getPropertyValue("--dark-blue").trim() || "#376eb6;";
      ctx.strokeStyle = strokeColor;
      ctx.lineWidth = 0.45;

      // Left Section (Col 0-2)
      const leftEnd = pl + colWidth * 2;
      ctx.save();
      ctx.beginPath();
      ctx.rect(pl, pt, leftEnd - pl, contentH);
      ctx.clip();

      // Fix: Start a new path so the clip rectangle isn't stroked
      ctx.beginPath();
      for (let x = pl; x < leftEnd + contentH; x += spacing) {
        ctx.moveTo(x, pt);
        ctx.lineTo(x - contentH, pt + contentH);
      }
      ctx.stroke();
      ctx.restore();

      // Right Section (Col 10-12)
      const rightStart = pl + colWidth * 10;
      ctx.save();
      ctx.beginPath();
      ctx.rect(rightStart, pt, parentWidth - pr - rightStart, contentH);
      ctx.clip();

      // Fix: Start a new path so the clip rectangle isn't stroked
      ctx.beginPath();
      for (let x = rightStart - contentH; x < parentWidth - pr; x += spacing) {
        ctx.moveTo(x, pt);
        ctx.lineTo(x + contentH, pt + contentH);
      }
      ctx.stroke();
      ctx.restore();

      // Vertical separators (The only inner borders we want)
      ctx.beginPath();
      ctx.moveTo(leftEnd, pt);
      ctx.lineTo(leftEnd, pt + contentH);
      ctx.moveTo(rightStart, pt);
      ctx.lineTo(rightStart, pt + contentH);
      ctx.stroke();
    }

    // --- Optimized Resize Management ---
    let timer;
    const observer = new ResizeObserver((entries) => {
      // If we are resizing, hide the canvas momentarily or skip drawing to save CPU
      clearTimeout(timer);
      timer = setTimeout(() => {
        performDraw();
      }, 100); // 100ms is a good sweet spot for responsiveness vs stability
    });

    observer.observe(parent);

    // Initial Draw
    performDraw();
  });
}

// Ensure the page is fully loaded so padding/widths are calculated correctly
if (document.readyState === "complete") {
  drawDiagonalBorders();
} else {
  window.addEventListener("load", drawDiagonalBorders);
}

document.addEventListener("DOMContentLoaded", () => {
  const buttons = document.querySelectorAll(".services-menu__button");
  buttons.forEach((btn) => {
    btn.addEventListener("click", () => {
      console.log("Service Menu Button Clicked");
      window.location.href = "";
    });
  });
});
